parameters.functionCode:
return $input.first().json.map(row => ({ json: {
  email: row.email,
  first_name: (row.full_name || '').split(' ')[0] || 'there',
  order_id: row.id,
  review_url: `https://sericia.com/review/${row.id}`
}}));

parameters.jsonBody:
={
  "from": "Sericia <contact@sericia.com>",
  "to": $json.email,
  "subject": "How was your Sericia drop, " + $json.first_name + "?",
  "html": `<div style=\"font-family:Georgia,serif;max-width:560px;margin:0 auto;color:#2b221c\"><h1 style=\"font-weight:normal\">A small favour, ${$json.first_name}.</h1><p>Your Sericia drop arrived a few days ago. If it matched the story we told — the producer, the season, the flavour — would you share a line or two so other buyers can find us?</p><p style=\"margin:28px 0\"><a href=\"${$json.review_url}\" style=\"background:#b8860b;color:white;padding:12px 28px;text-decoration:none;border-radius:4px\">Leave a 30-second review →</a></p><p>If something fell short instead, tell us — we read every reply.</p><p style=\"color:#6b5e4f;font-size:13px;margin-top:32px\">— Sericia · <a href=\"mailto:contact@sericia.com\">contact@sericia.com</a></p></div>`
}
